func TestExactValidators(t *testing.T) {
	extradData := ""
	if extradData[:2] == "0x" {
		extradData = extradData[2:]
	}
	extra, err := hex.DecodeString(extradData)
	if err != nil {
		t.Fatal(err)
	}

	validators := make([]common.Address, (len(extra)-ExtraVanity-ExtraSeal)/int(AddressLength))
	for i := 0; i < len(validators); i++ {
		copy(validators[i][:], extra[ExtraVanity+i*int(AddressLength):])
	}
	count := 0
	for _, validator := range validators {
		count++
		fmt.Println(validator.String())
	}
	fmt.Println("count", count)
}

