func TestExactM1sM2sFromCheckPointHeader(t *testing.T) {
	extraData := ""
	if extraData[:2] == "0x" {
		extraData = extraData[2:]
	}
	extra, err := hex.DecodeString(extraData)
	if err != nil {
		t.Fatal(err)
	}

	m1s := make([]common.Address, (len(extra)-ExtraVanity-ExtraSeal)/int(AddressLength))
	for i := 0; i < len(m1s); i++ {
		copy(m1s[i][:], extra[ExtraVanity+i*int(AddressLength):])
	}

	m2sIndex := ""
	m2sHex := m2sIndex
	if len(m2sHex) >= 2 && m2sHex[:2] == "0x" {
		m2sHex = m2sHex[2:]
	}
	m2sRaw, err := hex.DecodeString(m2sHex)
	if err != nil {
		t.Fatal(err)
	}
	attestorIdxs := DecodeAttestorsFromHeader(m2sRaw)
	if len(attestorIdxs) != len(m1s) {
		t.Fatalf("attestor index count %d != m1 count %d", len(attestorIdxs), len(m1s))
	}
	n := uint64(len(m1s))
	m2s := make([]common.Address, len(m1s))
	for i, idx := range attestorIdxs {
		attIdx := uint64(idx) % n
		m2s[i] = m1s[attIdx]
	}
	// Offset from TIP randomize (see eth/viction/validator.go getCreatorAttestorPairs) is 0 here — pass block number + config if needed.
	for i := range m1s {
		fmt.Printf("m1[%d]=%s m2[%d]=%s attestorIdx=%d\n", i, m1s[i].Hex(), i, m2s[i].Hex(), attestorIdxs[i])
	}
	fmt.Println("len(m1s)", len(m1s), "len(m2s)", len(m2s))
}

func decodeTestHex(t *testing.T, s string) []byte {
	t.Helper()
	s = strings.TrimPrefix(strings.TrimSpace(s), "0x")
	b, err := hex.DecodeString(s)
	if err != nil {
		t.Fatal(err)
	}
	return b
}

// TestRecoverSignerFromExtraData pastes only extraData here. The signature is over SealHash(header), so
// headerForRecoverSignerFixture must match the same block as that extra (from eth_getBlockByNumber).
func TestRecoverSignerFromExtraData(t *testing.T) {
	const extraHex = "0xda83010919846765746889676f312e31392e31338664617277696e0000000000d13e055509efbed271d2df23ba980baa411b04779f23c94d7dcfea008886ce1559eb224e2caef688c3add27be4be580ead9a5aa54752c3bcf7c8afaca498321300"

	extra := decodeTestHex(t, extraHex)
	if len(extra) < ExtraVanity+ExtraSeal {
		t.Fatalf("extra too short: got %d need >= %d", len(extra), ExtraVanity+ExtraSeal)
	}

	header := headerForRecoverSignerFixture(t, extra)

	signer, err := RecoverSignerFromHeader(header)
	fmt.Println("[POSV-miner]", signer.Hex())

	if err != nil {
		t.Fatalf("RecoverSignerFromHeader: %v", err)
	}
	if signer == (common.Address{}) {
		t.Fatal("recovered signer is zero")
	}
	if signer == header.Coinbase {
		t.Fatal("expected sealer from extraData seal, not etherbase")
	}
}

// headerForRecoverSignerFixture fills the preimage fields for SealHash. When you change extraHex to another
// block, copy parentHash, roots, number, gas, time, bloom, nonce from that block’s RPC header.
func headerForRecoverSignerFixture(t *testing.T, extra []byte) *types.Header {
	t.Helper()
	var nonce types.BlockNonce
	copy(nonce[:], decodeTestHex(t, "0x0000000000000000"))
	txRoot := common.HexToHash("0x56e81f171bcc55a6ff8345e692c0f86e5b48e01b996cadc001622fb5e363b421")
	// Block #51 (eth_getBlockByNumber) — parent is block #50 hash.
	return &types.Header{
		ParentHash:  common.HexToHash("0xf557c07658283f4a322036e7e20ae742e81eb7bd9dd1b9508727673d85573879"),
		UncleHash:   common.HexToHash("0x1dcc4de8dec75d7aab85b567b6ccd41ad312451b948a7413f0a142fd40d49347"),
		Coinbase:    common.Address{},
		Root:        common.HexToHash("0xb983832d94d09fd8dba0b91b6783cb317304f70918525b2fa230b3ad9060fdc6"),
		TxHash:      txRoot,
		ReceiptHash: txRoot,
		Bloom:       types.Bloom{},
		Difficulty:  big.NewInt(5),
		Number:      big.NewInt(51),
		GasLimit:    4939809,
		GasUsed:     0,
		Time:        1776051109,
		Extra:       extra,
		MixDigest:   common.Hash{},
		Nonce:       nonce,
	}
}
